import json
b = json.load(open('baseline-packages.json'))
a = json.load(open('after-cpm-packages.json'))

def pkg_map(data):
    m = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            for p in fw.get('topLevelPackages', []):
                m[(name, p['id'])] = p['resolvedVersion']
    return m

bm, am = pkg_map(b), pkg_map(a)
all_keys = sorted(set(bm) | set(am))
print(f'{'Project':<20} {'Package':<40} {'Before':<10} {'After':<10} Status')
print('-'*95)
for k in all_keys:
    bv, av = bm.get(k, 'N/A'), am.get(k, 'N/A')
    status = 'Unchanged' if bv == av else 'CHANGED'
    if status == 'CHANGED':
        print(f'{k[0]:<20} {k[1]:<40} {bv:<10} {av:<10} {status}')
print()
for k in all_keys:
    bv, av = bm.get(k, 'N/A'), am.get(k, 'N/A')
    if bv == av:
        print(f'{k[0]:<20} {k[1]:<40} {bv:<10} {av:<10} Unchanged')
"

